FETCH_ORG_INFO_FROM_ENTITY_GQL = '\nquery FetchOrgInfoFromEntity($entity: String!) {\n  entity(name: $entity) {\n    organization {\n      ...OrgInfoFragment\n    }\n    user {\n      organizations {\n        ...OrgInfoFragment\n      }\n    }\n  }\n}\n\nfragment OrgInfoFragment on Organization {\n  name\n  orgEntity {\n    name\n  }\n}\n'
FETCH_ORGANIZATION_GQL = '\nquery FetchOrganization($org: String!) {\n  organization(name: $org) {\n    id\n    name\n    orgEntity {\n      __typename\n      id\n      name\n      entityType\n    }\n  }\n}\n'
REGISTRY_VERSIONS_GQL = '\nquery RegistryVersions($organization: String!, $registryFilter: JSONString, $collectionFilter: JSONString, $artifactFilter: JSONString, $cursor: String, $perPage: Int, $order: String, $includeAliases: Boolean = false) {\n  organization(name: $organization) {\n    orgEntity {\n      name\n      artifactMemberships(\n        projectFilters: $registryFilter\n        collectionFilters: $collectionFilter\n        filters: $artifactFilter\n        after: $cursor\n        first: $perPage\n        order: $order\n      ) {\n        pageInfo {\n          ...PageInfoFragment\n        }\n        edges {\n          node {\n            ...ArtifactMembershipFragment\n          }\n        }\n      }\n    }\n  }\n}\n\nfragment ArtifactAliasFragment on ArtifactAlias {\n  __typename\n  id\n  alias\n}\n\nfragment ArtifactFragment on Artifact {\n  __typename\n  id\n  artifactSequence {\n    ...SourceCollectionInfoFragment\n  }\n  versionIndex\n  artifactType {\n    name\n  }\n  description\n  metadata\n  ttlDurationSeconds\n  ttlIsInherited\n  tags {\n    ...TagFragment\n  }\n  historyStep\n  state\n  size\n  digest\n  commitHash\n  fileCount\n  createdAt\n  updatedAt\n  aliases @include(if: $includeAliases) {\n    artifactCollection {\n      ...CollectionInfoFragment\n    }\n    ...ArtifactAliasFragment\n  }\n}\n\nfragment ArtifactMembershipFragment on ArtifactCollectionMembership {\n  __typename\n  id\n  versionIndex\n  aliases {\n    ...ArtifactAliasFragment\n  }\n  artifactCollection {\n    ...CollectionInfoFragment\n  }\n  artifact {\n    ...ArtifactFragment\n  }\n}\n\nfragment CollectionInfoFragment on ArtifactCollection {\n  __typename\n  name\n  project {\n    ...ProjectInfoFragment\n  }\n}\n\nfragment PageInfoFragment on PageInfo {\n  __typename\n  endCursor\n  hasNextPage\n}\n\nfragment ProjectInfoFragment on Project {\n  name\n  entity {\n    name\n  }\n}\n\nfragment SourceCollectionInfoFragment on ArtifactSequence {\n  __typename\n  name\n  project {\n    ...ProjectInfoFragment\n  }\n}\n\nfragment TagFragment on Tag {\n  __typename\n  id\n  name\n}\n'
REGISTRY_COLLECTIONS_GQL = '\nquery RegistryCollections($organization: String!, $registryFilter: JSONString, $collectionFilter: JSONString, $collectionTypes: [ArtifactCollectionType!] = [PORTFOLIO], $cursor: String, $perPage: Int, $order: String) {\n  organization(name: $organization) {\n    orgEntity {\n      name\n      artifactCollections(\n        projectFilters: $registryFilter\n        filters: $collectionFilter\n        collectionTypes: $collectionTypes\n        after: $cursor\n        first: $perPage\n        order: $order\n      ) {\n        totalCount\n        pageInfo {\n          ...PageInfoFragment\n        }\n        edges {\n          node {\n            __typename\n            ...RegistryCollectionFragment\n          }\n        }\n      }\n    }\n  }\n}\n\nfragment PageInfoFragment on PageInfo {\n  __typename\n  endCursor\n  hasNextPage\n}\n\nfragment ProjectInfoFragment on Project {\n  name\n  entity {\n    name\n  }\n}\n\nfragment RegistryCollectionFragment on ArtifactCollection {\n  __typename\n  id\n  name\n  description\n  createdAt\n  updatedAt\n  project {\n    ...ProjectInfoFragment\n  }\n  type: defaultArtifactType {\n    name\n  }\n  tags {\n    edges {\n      node {\n        ...TagFragment\n      }\n    }\n  }\n}\n\nfragment TagFragment on Tag {\n  __typename\n  id\n  name\n}\n'
FETCH_REGISTRY_GQL = '\nquery FetchRegistry($name: String, $entity: String) {\n  entity(name: $entity) {\n    project(name: $name) {\n      ...RegistryFragment\n    }\n  }\n}\n\nfragment RegistryFragment on Project {\n  __typename\n  id\n  name\n  entity {\n    name\n    organization {\n      name\n    }\n  }\n  description\n  createdAt\n  updatedAt\n  access\n  allowAllArtifactTypes: allowAllArtifactTypesInRegistry\n  artifactTypes(includeAll: true) {\n    edges {\n      node {\n        name\n      }\n    }\n  }\n}\n'
FETCH_REGISTRIES_GQL = '\nquery FetchRegistries($organization: String!, $filters: JSONString, $cursor: String, $perPage: Int, $order: String) {\n  organization(name: $organization) {\n    orgEntity {\n      projects(filters: $filters, after: $cursor, first: $perPage, order: $order) {\n        pageInfo {\n          ...PageInfoFragment\n        }\n        edges {\n          node {\n            ...RegistryFragment\n          }\n        }\n      }\n    }\n  }\n}\n\nfragment PageInfoFragment on PageInfo {\n  __typename\n  endCursor\n  hasNextPage\n}\n\nfragment RegistryFragment on Project {\n  __typename\n  id\n  name\n  entity {\n    name\n    organization {\n      name\n    }\n  }\n  description\n  createdAt\n  updatedAt\n  access\n  allowAllArtifactTypes: allowAllArtifactTypesInRegistry\n  artifactTypes(includeAll: true) {\n    edges {\n      node {\n        name\n      }\n    }\n  }\n}\n'
RENAME_REGISTRY_GQL = '\nmutation RenameRegistry($input: RenameProjectInput!) {\n  renameProject(input: $input) {\n    inserted\n    project {\n      ...RegistryFragment\n    }\n  }\n}\n\nfragment RegistryFragment on Project {\n  __typename\n  id\n  name\n  entity {\n    name\n    organization {\n      name\n    }\n  }\n  description\n  createdAt\n  updatedAt\n  access\n  allowAllArtifactTypes: allowAllArtifactTypesInRegistry\n  artifactTypes(includeAll: true) {\n    edges {\n      node {\n        name\n      }\n    }\n  }\n}\n'
UPSERT_REGISTRY_GQL = '\nmutation UpsertRegistry($input: UpsertModelInput!) {\n  upsertModel(input: $input) {\n    inserted\n    project {\n      ...RegistryFragment\n    }\n  }\n}\n\nfragment RegistryFragment on Project {\n  __typename\n  id\n  name\n  entity {\n    name\n    organization {\n      name\n    }\n  }\n  description\n  createdAt\n  updatedAt\n  access\n  allowAllArtifactTypes: allowAllArtifactTypesInRegistry\n  artifactTypes(includeAll: true) {\n    edges {\n      node {\n        name\n      }\n    }\n  }\n}\n'
DELETE_REGISTRY_GQL = '\nmutation DeleteRegistry($id: String!) {\n  deleteModel(input: {id: $id}) {\n    success\n  }\n}\n'
REGISTRY_USER_MEMBERS_GQL = '\nquery RegistryUserMembers($project: String!, $entity: String!) {\n  project(name: $project, entityName: $entity) {\n    members {\n      ...UserRegistryMemberFragment\n    }\n  }\n}\n\nfragment RegistryRoleFragment on Role {\n  name\n}\n\nfragment UserRegistryMemberFragment on ProjectMember {\n  id\n  name\n  username\n  email\n  role {\n    ...RegistryRoleFragment\n  }\n}\n'
REGISTRY_TEAM_MEMBERS_GQL = '\nquery RegistryTeamMembers($project: String!, $entity: String!) {\n  project(name: $project, entityName: $entity) {\n    teamMembers {\n      ...TeamRegistryMemberFragment\n    }\n  }\n}\n\nfragment RegistryRoleFragment on Role {\n  name\n}\n\nfragment TeamFragment on Entity {\n  __typename\n  id\n  name\n  available\n  photoUrl\n  readOnly\n  readOnlyAdmin\n  isTeam\n  entityType\n  privateOnly\n  storageBytes\n  codeSavingEnabled\n  defaultAccess\n  isPaid\n  members {\n    ...TeamMemberFragment\n  }\n}\n\nfragment TeamMemberFragment on Member {\n  __typename\n  id\n  role\n  pending\n  email\n  username\n  name\n  photoUrl\n  accountType\n  apiKey\n}\n\nfragment TeamRegistryMemberFragment on ProjectTeamMember {\n  team {\n    ...TeamFragment\n  }\n  role {\n    ...RegistryRoleFragment\n  }\n}\n'
CREATE_REGISTRY_MEMBERS_GQL = '\nmutation CreateRegistryMembers($input: CreateProjectMembersInput!) {\n  result: createProjectMembers(input: $input) {\n    success\n  }\n}\n'
DELETE_REGISTRY_MEMBERS_GQL = '\nmutation DeleteRegistryMembers($input: DeleteProjectMembersInput!) {\n  result: deleteProjectMembers(input: $input) {\n    success\n  }\n}\n'
UPDATE_USER_REGISTRY_ROLE_GQL = '\nmutation UpdateUserRegistryRole($input: UpdateProjectMemberInput!) {\n  result: updateProjectMember(input: $input) {\n    success\n  }\n}\n'
UPDATE_TEAM_REGISTRY_ROLE_GQL = '\nmutation UpdateTeamRegistryRole($input: UpdateProjectTeamMemberInput!) {\n  result: updateProjectTeamMember(input: $input) {\n    success\n  }\n}\n'
